window.__QUIZ_DATA__=[{"id":"theory>Biology>2015>PAPER II>PART I>1>a","subject":"Biology","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Explain briefly sexual reproduction in Rhizopus","images":[],"marking_scheme":"- By conjugation  - It is usually between two strain of hyphae;  - Known as + and -/plus and minus/opposite mating types;  - The hyphae come in contact;  - And produce small projections on their walls;  - Which develop into progametangia with several nuclei;  - The two progametangia enlarge;  - Each progametangium develops a cross wall to divide into two parts; the gametangium ans suspensor;  - Subsequently the wall dissolves/breaks; and their contents/nuclei fuse to form a zygote;  - The zygote develops a thick wall to form a resistant zygospore;  - The zygospore germinates during favorable/damp/wet condition;  - Into hyphae which bear sporangia.","marks":"8","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>1>b>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"A student suddenly stepped on a big snake, he cried for help and ran away.    Name the hormone produced in the body for the reaction.","images":[],"marking_scheme":"- Adrenalin/Adrenaline.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>1>b>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"A student suddenly stepped on a big snake, he cried for help and ran away.  In which part of the human body is the hormone named in 1(b)(i)  produced?","images":[],"marking_scheme":"- Adrenal gland/Medulla","marks":"1","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>1>b>iii","subject":"Biology","year":"2015","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"A student suddenly stepped on a big snake, he cried for help and ran away.  State five changes that must have taken place as a result of the hormone named in 1(b)(i)","images":[],"marking_scheme":"- Increase in heart beat  - Increase in rate of respiration;   - Arterioles of skin and alimentary canal constrict;  - Dialtion of blood vessels that cause more blood to flow to the muscles/heart/lungs;   - Increase in muscular tone/voluntary muscles become tensed;  - Glycogen is converted to glucose/increase in blood sugar level  - To produce more energy;  - Dilation of the pupil of the eye  - Momentary freight/fear/anxiety/heavy breathing   - Spleen release more red blood cells from its reserve  -  increase in blood pressure.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART I>1>c>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"In a tabular form, state three differences between excretion in flowering plants and excretion in humans","images":[],"marking_scheme":"Flowering Plants  Humans  - No definite excretory organs  Definite excretory organs - Waste product include tannins/resins/alkaloids/gums etc waste products include urine/urea/sweat/salts e.t.c.- Excretory product produce in small quantities  Excretory products produce in large quantities; - Excretory product release at a slower rate Excretory product release at a faster rate - Most excretory product (tannin/resins/alkaloids/gums) are stored Most excretory products are completely removed- Some excretory products (carbo dioxide,oxygen,water vapour) can be reused  Some excretory products (urea,uric acid) cannot be reused - Excretory products are derived from simple organic molecules  Excretory products are derived from complex organic molecules","marks":"3","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART I>1>c>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"List two organelles found in a plant cell that are responsible for the excretion of metabolic wastes","images":[],"marking_scheme":"- Mitochondrion/mitochondria; Chloroplast/chloroplasts","marks":"2","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>2>a","subject":"Biology","year":"2015","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Explain how the leaf of a flowering plant is adapted for photosynthesis","images":[],"marking_scheme":"- Broad/flat leaf lamella; exposes large surface area for maximum absorption of light;  - Palisade mesophyll cells contain a lot of chloroplast/chlorophyll; for maximum absorption of light.  - Position of leaf to stem ; for optimum reception of light rays/sunlight;  - Thin lamela; allows light penetration into leaf tissue of mesophyll;  - Palisade cells are at right angle.perpendicular to the upper epidermis/chloroplasts are arranged in the periphery of the cells; all for easy activation of the chloroplasts for photosynthesis;   -. Large vacuole of the palisade cells; store photosynthetic products  - Large intercellular air spaces in the spongy mesophyll; allows oxygen/carbon-dioxide to diffuse in/out of the chlorophyllus cells or gaseous exchange;   - The epidermal cells have thin cell walls; for easy penetration of sunlight to the mesophyll;  - Guard cells have chloroplast; for the absorption of sunlight;  - The bean-shaped structure of the guard cell; is to allow for gaseous exchange;  - The stomata; open easily when it becomes turgid for diffusion od gases/carbondioxide/oxygen;  - Xylem; conducts water into the leaves for photosynthesis;  - Phloem; transports manufactured food to other parts of the plant.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>2>b","subject":"Biology","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"Describe briefly the mode of feeding in tapeworm.","images":[],"marking_scheme":"Parasitic mode of feeding;; lives in the gut of man/pigs; has hooks/suckers; which enable it attach itself to th lining of the intestine of the host; has a flattened tape-like/ribbon-like body; provide large surface area for easy absorption of digested food; no alimentary/digestive systems.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>2>c>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Name one mineral element each needed for the proper functioning of bones","images":[],"marking_scheme":"- Calcium, Phosphate and Fluorine","marks":"1","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>2>c>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Name one mineral element each needed for the proper functioning of red blood cells","images":[],"marking_scheme":"- Iron; Copper","marks":"1","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>2>c>iii","subject":"Biology","year":"2015","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"Name one mineral element each needed for the proper functioning of thyroid gland","images":[],"marking_scheme":"- Iodine","marks":"1","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>2>d>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State three benefits of including roughage in the diet of humans","images":[],"marking_scheme":"- Stimulate bowel movement/peristalsis;   - Reduces blood cholesterol/bowel cancer/gall stones/appendicitis/obesity/diabetes mellitus;  - They do not contribute to weight gain/high blood sugar;  - It releases glucose slowly;  - It prevents constipation.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>2>d>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State three reasons why proteins are important to humans","images":[],"marking_scheme":"- For the repair of damaged tissues; replacement of worn-out tissues.  - For body building;  - For growth;  - For the supply of the necessary amino acids;  - For formation of hormones/enzymes/antibodies/fibronogen necessary for blood clotting.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>3>a>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"What is sewage?","images":[],"marking_scheme":"- Waste matter/faeces/urine/waste water from animals/industrial/domestic sources; that is dissolved/suspended in water.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>3>a>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State five effects of releasing untreated sewage into a stagnant water body.","images":[],"marking_scheme":"- Spread of water-borne diseases/correctly named diseases/microbes/pathogens;  - May be toxic/poisonous to aquatic life/organisms;  - Make water unfit for consumption/use;  - Increased decomposition;  - Increased concentration of nutrients;   - Rapid growth of algea/aquatic plants/algal bloom/eutrophication;  - Depletion of oxygen;  - Suffocation/death of aquatic animals;  - Generates offensive odour/air pollution;  - Nutrient/nitrate/phosphate enrichment/accumulation in a water body; as a result of breakdown by bacteria.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>3>b","subject":"Biology","year":"2015","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Explain a surface terracing as a soil conservation method.","images":[],"marking_scheme":"- A method of controlling erosion on a gentle/steep slope of hill; flat horizontal areas are constructed on which crops are cultivated; flowing the contour; steps/walls are built along th contours; ploughing is also done along the contours; reduces the speed of water running down the slopes","marks":"3","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>3>c","subject":"Biology","year":"2015","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Explain the term adaptation.","images":[],"marking_scheme":"- Is the possession of the characteristic/trait/behaviour/structure /feature that evolved over a period of time, which enables an organism to survive and reproduce in response to changes in the enviroment/habitat.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART I>3>d>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain two ways by which this organism adapt to its environment :    hydrophytes","images":[],"marking_scheme":"- Some hydrophytes lack/have reduced roots/root hairs/root caps;   - do not need firm anchorage in water/wetland;  - Presence of large air space/aerenchyma in roots/leaves; provide support for boyancy;  - Presence of hairs on the leaves; to prevent blockage of the stomata;  - Stomatal pores; occur  present only at the upper epidermis of the leaves to aid transpiration/loss of water;  - Presence of numerous adventitious roots and root hairs for absorption of water/mineral salts;  - small size of the plant; for buoyancy/floating in water;  - waxy upper surface of the leaf; to prevent clogging of the leaf by water;  - long petiole/leaf stalk to support /expose the broad lamina for photosynthesis;  - long flower stalk/pedicel; to expose flower for pollination/pollinating agents;  - Presence of  breathing roots /pneumatophores; for breathing/gaseous exchange.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART I>3>d>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain two ways by which this organism adapt to its environment :  - Xerophytes","images":[],"marking_scheme":"- Possession of thick succulent leaves/stem for storing water;  - Reduction of leaves to spines; to reduce water loss/rate of transpiration  - Thick waxy cuticle on epidermis to reduce water-loss/transpiration;   - Possession of long tap root system; to obtain water from great depth of soil;  - Presence of sunken stomata; to reduce water loss;  - reduced number of stomata; to prevent excessive water loss;  - presence of multiple epidermal layers; for water conservation/to reduce water loss.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>4>a>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain the term.    test cross","images":[],"marking_scheme":"- This is the crossing/mating of an organism of unknown genotype; with a homozygous recessive/double recessive organism, to determine the genotype of an organism.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART II>4>a>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain the term.  monohybrid cross","images":[],"marking_scheme":"- Is a genetic cross between parents; that differ in the alleles they possess; for one particular gene.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART II>4>b>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a mango plant, the allele for bean-shaped is r and is recessive to round-shaped seed R. With the aid of a genetic diagram, determine the genotype of the offspring if:    A homozygous bean-shaped parent is crossed with a homozygous round shaped parents","images":["data:image/png;base64,"],"marking_scheme":"","marks":"16","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART II>4>b>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a mango plant, the allele for bean-shaped is r and is recessive to round-shaped seed R. With the aid of a genetic diagram, determine the genotype of the offspring if:  A heterozygous bean-shaped parent is crossed with a heterozygous round shaped parents","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART II>5>a","subject":"Biology","year":"2015","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Copy and complete the table below  DiseaseOne effectOne remedyKidney stoneNephritisDuiresis","images":[],"marking_scheme":"Kidney diseases    DiseaseOne effectOne remedyKidney stoneAbdominal pains increased blood, decreased frequency of urination  Drink plenty of water, kidney transplant, avoid food rich in calcium/red/meat/consult a doctorNephritisOedema, high blood pressure, blood in urine, dizziness/back pain/fatigue, general weakness,inflammation of kidney tubulesConsult a physician, kidney transplant, dialysis, drinking water sterilized.DuiresisThirst/dehydration, loss of appetite, weakness, fatigue, nausea, loss of serum eletrolyteConsult a physician, avoid fans/air conditions in cold weather avoid excessive drinking of alcohol","marks":"6","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>5>b","subject":"Biology","year":"2015","type":"Theory","sub_label":"b","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Make a label diagram of the carbon cycle","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>5>c>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"What is Estuarine habitat?","images":[],"marking_scheme":"- Is the place/point where a river enters the ocean/sea; into which the tides flow; fresh water mixes with salt water; to form brackish water.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2015>PAPER II>PART II>5>c>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Construct a food chain typical of an estuarine habitat","images":[],"marking_scheme":"Phytoplanktons>>barbacles>>fish>>bird OR  Detritus>>worm>>mollusc>>bird OR  Detritus>>shrimp>>fish>>bird","marks":"2","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>5>d>i","subject":"Biology","year":"2015","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"Name two pest and two diseases that can attack plant crops.","images":[],"marking_scheme":"- Stem borer  - Army worm  - Weevils  - Black tea-thrips   - aphrids  - root mealybugs  - variegated grasshopper  - beetle  - rodents  - squirrel  - loscuts  - birds  - mites  - cotton stainer      Diseases that can attack plant crops  - Leaf spot, Cancer; Rosette; rice blast; root knots; swollen shoot of cocoa; sigatoka; black pod  of cocoafreckle; root/stem rots; bacteria blight; smut; mildew; powdery mildew","marks":"2","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>5>d>ii","subject":"Biology","year":"2015","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"State three way of controlling plant diseases","images":[],"marking_scheme":"- Chemical control/use of fungicide/nematicides/bactericides/pesticides;  - Biological control/use of predators and parasites of insects/pests to keep them in check;  - Breeding resistant varieties of crop;  - Planting genetically modified crops that can resist viruses/bacteria transmitted by pests;  - Destruction of infested crops by burning/deep burial/pruning of affected parts;  - Destruction of alternate host  - Adopt good management/crop rotation.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2015>PAPER II>PART II>5>e","subject":"Biology","year":"2015","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"State four functions of a public health authority.","images":[],"marking_scheme":"- Ensures cleanliness of public places/markets/schools/playgrounds;  - Concerned with the proper disposal of refuse;  - Provides maternity clinics/health centres/nursing homes/family planting;  - provides child welfare services;  - Provides medical inspection of schools;  - registers birth/death;  - prevents/controls infectious diseases/administers vaccination/immunization/inoculation;  - informs World Health Organization of the outbreak of infectious diseases;  - ensures adequate provision of clean water to the public;  - provides ambulance services;  - provides quarantine services for plants/animals/humans;  - gives health certificate to travellers;  - provides public health education/awareness of diseases;  - inspects and certifies health of animals and cleanliness of slaughter house/abattoir","marks":"4","difficulty":"3"},{"id":"theory>Biology>2015>PAPER II>PART II>5>f","subject":"Biology","year":"2015","type":"Theory","sub_label":"f","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"State four ways of maintaining food hygiene in the community","images":[],"marking_scheme":"- Proper harvesting/storage methods must be ensured to prevent damage to food items;  - Food items must be properly washed/cleaned to prevent contamination;  - Food items must be properly cooked at appropriate temperatures;  - Kitchen/cooking areas must be kept clean always/free from germs;  - Perishable food items must be properly preserved/refrigerated;  - Proper personal hygiene must be observed by those handling food;  - cooking utensils must be properly washed/cleaned before and after use;  - cooked/prepared food must be covered at all time;  - proper disposal of unused/leftover food.","marks":"4","difficulty":"1"}];